func TestReconcileTriggersOnDeleteOfConflictingDriver(t *testing.T) {
	scheme := runtime.NewScheme()
	require.NoError(t, nvidiav1alpha1.AddToScheme(scheme))
	require.NoError(t, gpuv1.AddToScheme(scheme))
	require.NoError(t, corev1.AddToScheme(scheme))

	// Create a node that matches both drivers
	node := &corev1.Node{
		ObjectMeta: metav1.ObjectMeta{
			Name: "gpu-node",
			Labels: map[string]string{
				"nvidia.com/gpu.present": "true",
			},
		},
	}

	// Create default driver (no explicit nodeSelector, so gets default nvidia.com/gpu.present label)
	defaultDriver := &nvidiav1alpha1.NVIDIADriver{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "default-driver",
			Namespace: "default",
		},
	}

	// Create a custom driver with same effective selector
	customDriver := &nvidiav1alpha1.NVIDIADriver{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "custom-driver",
			Namespace: "default",
		},
	}

	cp := &gpuv1.ClusterPolicy{
		ObjectMeta: metav1.ObjectMeta{Name: "default"},
		Spec: gpuv1.ClusterPolicySpec{
			Driver: gpuv1.DriverSpec{
				UseNvidiaDriverCRD: ptr.To(true),
			},
		},
	}

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(cp, node, defaultDriver, customDriver).Build()
	updater := &FakeConditionUpdater{}

	// Create a real nodeSelectorValidator
	realValidator := validator.NewNodeSelectorValidator(client)
	recordingValidator := &RecordingNodeSelectorValidator{inner: realValidator}

	reconciler := &NVIDIADriverReconciler{
		Client:                client,
		Scheme:                scheme,
		conditionUpdater:      updater,
		nodeSelectorValidator: recordingValidator,
		stateManager:          &FakeStateManager{},
	}

	// Step 1: Reconcile custom-driver first while default-driver still exists
	// This should fail with a conflict because default-driver has no explicit selector
	// matching the same nvidia.com/gpu.present labeled node
	req := ctrl.Request{
		NamespacedName: types.NamespacedName{
			Name:      customDriver.Name,
			Namespace: customDriver.Namespace,
		},
	}
	_, err := reconciler.Reconcile(context.Background(), req)
	require.NoError(t, err)
	require.Equal(t, nvidiav1alpha1.NotReady, updater.LastErrorState)

	// Step 2: Simulate deletion of the default driver by removing it from the fake client
	require.NoError(t, client.Delete(context.Background(), defaultDriver))

	// Reset calls and state
	recordingValidator.ValidateCalls = nil
	updater.LastErrorState = ""

	// Step 3: Reconcile the custom-driver again after default is deleted
	_, err = reconciler.Reconcile(context.Background(), req)
	require.NoError(t, err)

	// After the default driver is deleted, the custom driver should pass validation
	// since there's no longer a conflict
	// The validator should have been called for the custom-driver
	require.Contains(t, recordingValidator.ValidateCalls, customDriver.Name)
}

