	require.NoError(t, client.Delete(context.Background(), defaultDriver))

	// Step 3: Verify the default driver is actually gone
	drivers := &nvidiav1alpha1.NVIDIADriverList{}
	require.NoError(t, client.List(context.Background(), drivers))
	require.Len(t, drivers.Items, 1)
	require.Equal(t, customDriver.Name, drivers.Items[0].Name)

	// Step 4: Verify that after default driver is deleted, validation passes for custom-driver
	// (the conflict is resolved)
